const request = items[0]?.json || {};
const input = request.body || request;
const payload = input.payload || {};
const description = String(payload.description || '').trim();
const descriptionLower = description.toLowerCase();
const priority = String(payload.priority || '0');
const photoCount = Number(payload.photo_count || 0);
let aiDisposition = 'sellable';
let aiConfidence = 0.62;
let aiRecommendedAction = 'Sichtpruefung durch Qualitaetsteam.';
if (priority === '3' || /(totalschaden|zerstoert|eingedrueckt|bruch|gebrochen)/.test(descriptionLower)) {
  aiDisposition = 'scrap';
  aiConfidence = 0.94;
  aiRecommendedAction = 'Ware sperren, aussondern und Schichtleitung informieren.';
} else if (priority === '2' || photoCount > 0 || /(defekt|gerissen|feucht|nass|offen|beschaedigt)/.test(descriptionLower)) {
  aiDisposition = 'quarantine';
  aiConfidence = 0.87;
  aiRecommendedAction = 'Ware sperren und manuelle Pruefung anfordern.';
} else if (/(kratzer|etikett|verpackung|kleber|nacharbeit)/.test(descriptionLower)) {
  aiDisposition = 'rework';
  aiConfidence = 0.79;
  aiRecommendedAction = 'Nacharbeit pruefen und Verpackung korrigieren.';
}
const severityLabel = priority === '3' ? 'kritisch' : priority === '2' ? 'hoch' : 'normal';
const aiSummary = description
  ? `Automatische V1-Bewertung (${severityLabel}): ${description}`
  : `Automatische V1-Bewertung fuer Alert ${payload.alert_id || ''}.`;
return [{ json: {
  correlation_id: input.correlation_id,
  alert_id: payload.alert_id,
  ai_disposition: aiDisposition,
  ai_confidence: aiConfidence,
  ai_summary: aiSummary,
  ai_recommended_action: aiRecommendedAction,
  ai_provider: 'n8n-heuristic-agent',
  ai_model: 'quality-v1',
  log_message: `Alert ${payload.name || payload.alert_id}: ${aiDisposition} | Prioritaet ${priority} | ${description || 'ohne Beschreibung'}`,
} }];
